import React from 'react';
import clsx from 'clsx';
import ListCheckBoldOutlined from '@universe-design/icons-react/ListCheckBoldOutlined';
import { useTreeContext } from './hooks/TreeContext';
import { useTreeNodeContext } from './hooks/TreeNodeContext';

export const TreeNodeCheckmark = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<'div'>>(
  ({ className, ...restProps }, ref) => {
    const { rootCssScope, showChecker } = useTreeContext();
    const { isSelected } = useTreeNodeContext();
    return showChecker ? (
      <div ref={ref} className={clsx(rootCssScope('__node__checker'), className)} {...restProps}>
        {isSelected ? <ListCheckBoldOutlined /> : null}
      </div>
    ) : null;
  },
);
